        let last_page = ((total + per_page - 1) / per_page).max(1);
        let current_page = page.min(last_page);
        let offset_val = (current_page - 1) * per_page;
        let mut sql = format!("SELECT {} {}{}", select_clause, from_clause, where_clause);
